  "questionProse": [
    "हैश टेबल में किसी एलिमेंट को एक्सेस करने की औसत टाइम कॉम्प्लेक्सिटी क्या होती है?"
  ],
  "explanationProse": [
    "हैश टेबल्स में एलिमेंट्स को एक्सेस करने की औसत टाइम कॉम्प्लेक्सिटी O(1) होती है, बशर्ते कि आपका हैश फंक्शन सॉलिड हो और कॉलिज़न्स (collisions) न्यूनतम हों।"
  ]
}
